```typescript
class Fighter {
    private skel: sp.SkeletonAnimation;
    private damage: number = 25;

    attack(target: { takeDamage(amount: number): void }): void {
        const track = this.skel.setAnimation(0, 'attack', false);
        if (track) {
            track.timeScale = 1.5;
        }

        this.skel.setAnimationListener(this, (
            trackEntry: spine.TrackEntry,
            type: number,
            event: spine.Event
        ) => {
            if (type === sp.AnimationEventType.EVENT && event.data.name === 'hit') {
                target.takeDamage(this.damage);
            }
            if (type === sp.AnimationEventType.COMPLETE) {
                this.skel.setAnimation(0, 'idle', true);
            }
        });
    }
}
```

The `track.timeScale = 1.5` speeds up only this track's playback. The listener checks for the custom 'hit' event to apply damage at the precise animation frame, and returns to idle on completion.

