    trackEntry: spine.TrackEntry,
    type: number,
    event: spine.Event
): void => {
    if (type === sp.AnimationEventType.EVENT) {
        const name: string = event.data.name;
        cc.log(name);
    }
};
skel.setAnimationListener(this, callback);
```

Both methods return nullable types:

```typescript
findBone(boneName: string): spine.Bone | null
findSlot(slotName: string): spine.Slot | null
```

They return `null` when the specified bone or slot name doesn't exist in the skeleton data.

```typescript
const skel = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');

const bone: spine.Bone | null = skel.findBone('head');
if (bone) {
    const x: number = bone.worldX;
    const y: number = bone.worldY;
}

const slot: spine.Slot | null = skel.findSlot('weapon_slot');
