class AnimatedCharacter extends cc.Layer {
    private skel: sp.SkeletonAnimation;

    private static readonly SFX_MAP: { [key: string]: string } = {
        'footstep': 'res/audio/sfx_step.mp3',
        'sword_swing': 'res/audio/sfx_swing.mp3',
        'hit_impact': 'res/audio/sfx_hit.mp3',
        'land': 'res/audio/sfx_land.mp3'
    };

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        this.preloadSounds();
        this.setupSkeleton();
        this.setupAnimationListener();
        return true;
    }

    private preloadSounds(): void {
        for (const key in AnimatedCharacter.SFX_MAP) {
            cc.audioEngine.preloadEffect(AnimatedCharacter.SFX_MAP[key]);
        }
    }

    private setupSkeleton(): void {
        this.skel = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.skel.setPosition(240, 160);
        this.addChild(this.skel);

        this.skel.setMix('idle', 'run', 0.2);
        this.skel.setMix('run', 'idle', 0.2);
        this.skel.setMix('run', 'jump', 0.1);
        this.skel.setMix('jump', 'idle', 0.2);
        this.skel.setMix('idle', 'attack', 0.1);
        this.skel.setMix('attack', 'idle', 0.2);

        this.skel.setAnimation(0, 'idle', true);
    }

    private setupAnimationListener(): void {
        this.skel.setAnimationListener(this, (
            track: spine.TrackEntry,
            type: number,
            event: spine.Event
        ) => {
            if (type === sp.AnimationEventType.EVENT) {
                this.onSpineEvent(event);
            }
            if (type === sp.AnimationEventType.COMPLETE && !track.loop) {
                this.skel.setAnimation(0, 'idle', true);
            }
        });
    }

    private onSpineEvent(event: spine.Event): void {
        const sfxPath = AnimatedCharacter.SFX_MAP[event.data.name];
        if (sfxPath) {
            cc.audioEngine.playEffect(sfxPath);
        }
    }

    playRun(): void {
        this.skel.setAnimation(0, 'run', true);
    }

    playAttack(): void {
        this.skel.setAnimation(0, 'attack', false);
    }
}
```

This integrates Spine events with audio playback. A static map links Spine event names to sound file paths. Sounds are preloaded at init. The animation listener fires `playEffect` whenever a matching Spine event occurs, keeping audio perfectly synchronized with animation frames.

