class SlowMotionController {
    private skel: sp.SkeletonAnimation;
    private targetScale: number = 1.0;
    private currentScale: number = 1.0;
    private restoreSpeed: number = 0;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    triggerSlowMotion(scale: number, duration: number): void {
        this.currentScale = scale;
        this.targetScale = 1.0;
        this.restoreSpeed = (1.0 - scale) / duration;
        this.skel.setTimeScale(scale);
    }

    update(dt: number): void {
        if (this.currentScale < this.targetScale) {
            this.currentScale = Math.min(
                this.currentScale + this.restoreSpeed * dt,
                this.targetScale
            );
            this.skel.setTimeScale(this.currentScale);
        }
    }
}

// Usage in a layer:
class GameLayer extends cc.Layer {
    private hero: sp.SkeletonAnimation;
    private slowMo: SlowMotionController;

    init(): boolean {
        this.hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.hero.setPosition(240, 160);
        this.addChild(this.hero);
        this.hero.setAnimation(0, 'run', true);

        this.slowMo = new SlowMotionController(this.hero);
        this.scheduleUpdate();
        return true;
    }

    onHitConfirm(): void {
        this.slowMo.triggerSlowMotion(0.2, 1.0);
    }

    update(dt: number): void {
        this.slowMo.update(dt);
    }
}
```

Calling `triggerSlowMotion(0.2, 1.0)` drops to 20% speed and linearly restores to normal over 1 second. The controller uses `setTimeScale` which affects all tracks globally.

