```typescript
class DamageFlashController {
    private skel: sp.SkeletonAnimation;
    private layer: cc.Layer;
    private isFlashing: boolean = false;

    private static readonly FLASH_DURATION = 0.1;
    private static readonly FLASH_COUNT = 3;

    constructor(skel: sp.SkeletonAnimation, layer: cc.Layer) {
        this.skel = skel;
        this.layer = layer;
    }

    triggerDamageEffect(): void {
        if (this.isFlashing) return;
        this.isFlashing = true;

        // Briefly pause animation
        const originalScale = this.skel.getTimeScale();
        this.skel.setTimeScale(0);

        // Play hit reaction on overlay track
        const hitTrack = this.skel.setAnimation(1, 'hit_react', false);
        if (hitTrack) {
            hitTrack.alpha = 0.7;
        }

        // Flash visibility
        let flashCount = 0;
        const flashCallback = () => {
            this.skel.setVisible(!this.skel.isVisible());
            flashCount++;
            if (flashCount >= DamageFlashController.FLASH_COUNT * 2) {
                this.skel.setVisible(true);
                this.skel.setTimeScale(originalScale);
                this.skel.clearTrack(1);
                this.isFlashing = false;
                this.layer.unschedule(flashCallback);
            }
        };

        // Resume after brief freeze
        this.layer.scheduleOnce(() => {
            this.skel.setTimeScale(originalScale);
            this.layer.schedule(
                flashCallback,
                DamageFlashController.FLASH_DURATION
            );
        }, 0.05);
    }
}

// Usage:
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setAnimation(0, 'idle', true);
const flash = new DamageFlashController(hero, this);
flash.triggerDamageEffect();
```

This combines `setTimeScale(0)` for a hit-freeze, an overlay animation on track 1 with partial alpha for a hit reaction, and scheduled visibility toggling for a flash effect.

