class BoneTracker extends cc.Layer {
    private skel: sp.SkeletonAnimation;
    private particle: cc.ParticleSystem;

    init(): boolean {
        this.skel = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.skel.setPosition(240, 160);
        this.addChild(this.skel);
        this.skel.setAnimation(0, 'run', true);

        this.particle = new cc.ParticleSystem('res/particles/dust.plist');
        this.addChild(this.particle);

        this.scheduleUpdate();
        return true;
    }

    update(dt: number): void {
        this.skel.updateWorldTransform();

        const bone = this.skel.findBone('foot_r');
        if (bone) {
            const worldX = this.skel.getPositionX() + bone.worldX;
            const worldY = this.skel.getPositionY() + bone.worldY;
            this.particle.setPosition(worldX, worldY);
        }
    }
}
