const TRACK = {
    BODY: 0,
    ARMS: 1,
    EFFECTS: 2
} as const;

class FighterAnimationSystem {
    private skel: sp.SkeletonAnimation;

    constructor(jsonPath: string, atlasPath: string) {
        this.skel = new sp.SkeletonAnimation(jsonPath, atlasPath);
        this.setupMixes();
        this.setupListener();
    }

    getSkeleton(): sp.SkeletonAnimation {
        return this.skel;
    }

    private setupMixes(): void {
        this.skel.setMix('idle', 'walk', 0.15);
        this.skel.setMix('walk', 'idle', 0.15);
        this.skel.setMix('idle', 'crouch', 0.1);
        this.skel.setMix('crouch', 'idle', 0.1);
    }

    private setupListener(): void {
        this.skel.setAnimationListener(this, (
            track: spine.TrackEntry,
            type: number,
            event: spine.Event
        ) => {
            if (type === sp.AnimationEventType.COMPLETE && !track.loop) {
                this.onNonLoopComplete(track);
            }
        });
    }

    private onNonLoopComplete(track: spine.TrackEntry): void {
        const current = this.skel.getCurrent(TRACK.BODY);
        if (current && current.animation.name !== 'idle') return;
        this.skel.setAnimation(TRACK.BODY, 'idle', true);
    }

    setBodyAnimation(name: string, loop: boolean): void {
        this.skel.setAnimation(TRACK.BODY, name, loop);
    }

    setArmsAnimation(name: string, loop: boolean, alpha: number = 1.0): void {
        const track = this.skel.setAnimation(TRACK.ARMS, name, loop);
        if (track) {
            track.alpha = alpha;
        }
    }

    playEffect(name: string): void {
        const track = this.skel.setAnimation(TRACK.EFFECTS, name, false);
        if (track) {
            track.alpha = 0.8;
        }
    }

    punch(): void {
        this.setBodyAnimation('punch_body', false);
        this.setArmsAnimation('punch_arms', false);
        this.playEffect('punch_vfx');
    }

    block(): void {
        this.setArmsAnimation('block_arms', true, 0.9);
    }

    idle(): void {
        this.setBodyAnimation('idle', true);
        this.skel.clearTrack(TRACK.ARMS);
        this.skel.clearTrack(TRACK.EFFECTS);
    }
}

// Usage:
const fighter = new FighterAnimationSystem('res/fighter/fighter.json', 'res/fighter/fighter.atlas');
const skel = fighter.getSkeleton();
skel.setPosition(240, 80);
this.addChild(skel);
fighter.idle();
fighter.punch();
```

Track 0 handles body locomotion, track 1 handles arm overlays (blocking, punching), and track 2 handles visual effects. Each track can be controlled independently with different alpha values for partial blending.

```typescript
const UNINTERRUPTIBLE_ANIMS = ['death', 'ultimate', 'stun'] as const;

class AnimationGuard {
    private skel: sp.SkeletonAnimation;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    private isCurrentUninterruptible(): boolean {
        const current = this.skel.getCurrent(0);
        if (!current) return false;
        const name = current.animation.name;
        return (UNINTERRUPTIBLE_ANIMS as readonly string[]).indexOf(name) !== -1;
    }

    trySetAnimation(name: string, loop: boolean): spine.TrackEntry | null {
        if (this.isCurrentUninterruptible()) {
            cc.log('Cannot interrupt: ' + this.skel.getCurrent(0).animation.name);
            return null;
        }
        return this.skel.setAnimation(0, name, loop);
    }

    forceSetAnimation(name: string, loop: boolean): spine.TrackEntry | null {
        return this.skel.setAnimation(0, name, loop);
    }

    getCurrentAnimationName(): string | null {
        const current = this.skel.getCurrent(0);
        return current ? current.animation.name : null;
    }
}

// Usage:
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
const guard = new AnimationGuard(hero);

guard.trySetAnimation('idle', true);      // plays idle
guard.forceSetAnimation('death', false);  // forces death
guard.trySetAnimation('run', true);       // blocked â€” death is uninterruptible
```

`getCurrent(trackIndex)` returns the active `spine.TrackEntry` on that track, or `null` if nothing is playing. This lets you inspect the current animation name before deciding whether to allow a transition.

```typescript
declare namespace spine {
    interface Animation {
        readonly name: string;
    }

    interface TrackEntry {
        /** The animation being played on this track */
        readonly animation: Animation;

        /** Whether this animation loops */
        loop: boolean;

        /** Delay in seconds before the animation starts (for queued entries) */
        delay: number;

        /** Current playback time in seconds */
        trackTime: number;

        /** Time at which the track ends (duration for non-looping) */
        trackEnd: number;

        /** Per-track speed multiplier (1.0 = normal) */
        timeScale: number;

        /** Blend weight 0â€“1 for mixing with lower tracks */
        alpha: number;

        /** Crossfade duration in seconds when transitioning into this animation */
        mixDuration: number;

        /** Returns the current animation time accounting for looping */
        getAnimationTime(): number;
    }
}
```

This covers all properties and methods documented for `spine.TrackEntry`. `animation` is read-only since it's set by `setAnimation`/`addAnimation`. The writable properties (`loop`, `delay`, `timeScale`, `alpha`, `mixDuration`) can be modified at runtime to adjust playback behavior.

`setStartListener` and `setEndListener` are convenience methods that register callbacks for specific animation lifecycle events, as an alternative to the general `setAnimationListener`:

```typescript
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setPosition(240, 160);
this.addChild(hero);

// Fires when any animation starts playing
hero.setStartListener((trackEntry: spine.TrackEntry) => {
    cc.log('Started: ' + trackEntry.animation.name);
});

// Fires when any animation ends (interrupted or cleared)
hero.setEndListener((trackEntry: spine.TrackEntry) => {
    cc.log('Ended: ' + trackEntry.animation.name);
});

hero.setAnimation(0, 'idle', true);  // triggers start listener
hero.setAnimation(0, 'run', true);   // triggers end for 'idle', start for 'run'
hero.clearTrack(0);                   // triggers end for 'run'
```

Unlike `setAnimationListener`, these individual listeners receive only the `TrackEntry` (no type or event parameters). They apply globally to all tracks. Use these when you only care about start/end events and want simpler callback signatures.
